// ─── AUTO-TRACK: watch CLI logs for new submissions ─────────────────────────

function readInputs() {
  try { return JSON.parse(fs.readFileSync(INPUTS_FILE, 'utf8')); } catch { return {}; }
}
function writeInputs(map) {
  fs.writeFileSync(INPUTS_FILE, JSON.stringify(map, null, 2));
}
function readHidden() {
  try { return JSON.parse(fs.readFileSync(HIDDEN_FILE, 'utf8')); } catch { return []; }
}
function writeHidden(list) {
  fs.writeFileSync(HIDDEN_FILE, JSON.stringify(list, null, 2));
}
function readLiked() {
  try { return JSON.parse(fs.readFileSync(LIKED_FILE, 'utf8')); } catch { return []; }
}
function writeLiked(list) {
  fs.writeFileSync(LIKED_FILE, JSON.stringify(list, null, 2));
}

let logWatchState = { file: null, offset: 0 };

function getTodayLogDir() {
  const d = new Date();
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return path.join(CLI_LOGS_DIR, y + '-' + m + '-' + day);
}

function getLatestLog() {
  const dir = getTodayLogDir();
  try {
    const files = fs.readdirSync(dir).filter(f => f.endsWith('.log')).sort();
    if (!files.length) return null;
    return path.join(dir, files[files.length - 1]);
  } catch { return null; }
}

function parseSubmitFromLine(line) {
  // [SubmitTask] line has all the info we need
  if (!line.includes('[SubmitTask]')) return null;
  const inputMatch = line.match(/input=(\{.*\})\s+logid=/);
  if (!inputMatch) return null;
  try {
    const input = JSON.parse(inputMatch[1]);
    return {
      logid: (line.match(/logid=(\S+)/) || [])[1] || '',
      task_type: (line.match(/gen_task_type=(\S+)/) || [])[1] || '',
      model: input.model_version || '',
      ratio: input.ratio || '',
      duration: String(input.duration || ''),
      files: [].concat(input.image_paths || [], input.video_paths || [], input.audio_paths || []).filter(Boolean)
    };
  } catch { return null; }
}

function parseSubmitIdFromLine(line) {
  // After [ResourceUpload] or [SubmitGenTask], submit_id appears at end of log line
  const m = line.match(/submit_id=([0-9a-f]{16})/);
  return m ? m[1] : null;
}

// Pending submissions: logid → parsed data (waiting for submit_id)
let pendingSubmits = {};

function processLogLine(line) {
  // Step 1: capture SubmitTask with all metadata (submit_id not yet known)
  const submit = parseSubmitFromLine(line);
  if (submit && submit.logid) {
    pendingSubmits[submit.logid] = submit;
    return;
  }

  // Step 2: once submit_id appears (in upload or query lines), match by logid
  const sid = parseSubmitIdFromLine(line);
  if (!sid || sid === '-') return;
  const logidMatch = line.match(/logid=(\S+)/);
  if (!logidMatch) return;
  const logid = logidMatch[1];

  if (pendingSubmits[logid]) {
    const data = pendingSubmits[logid];
    const map = readInputs();
    if (!map[sid]) {
      map[sid] = {};
      if (data.files.length) map[sid].files = data.files;
      if (data.model) map[sid].model = data.model;
      if (data.ratio) map[sid].ratio = data.ratio;
      if (data.duration) map[sid].duration = data.duration;
      writeInputs(map);
      console.log('[auto-track] Captured submit ' + sid + ' → ' + data.model + ' ' + data.ratio + ' ' + data.duration + 's, ' + data.files.length + ' files');
    }
    delete pendingSubmits[logid];
  }
}

function pollLogs() {
  const latest = getLatestLog();
  if (!latest) return;

  // If log file changed, reset offset
  if (latest !== logWatchState.file) {
    logWatchState.file = latest;
    logWatchState.offset = 0;
    // On first read, skip to end (don't reprocess old logs)
    try {
      const stat = fs.statSync(latest);
      logWatchState.offset = stat.size;
    } catch {}
    return;
  }

  try {
    const stat = fs.statSync(latest);
    if (stat.size <= logWatchState.offset) return;

    const stream = fs.createReadStream(latest, { start: logWatchState.offset, encoding: 'utf8' });
    let buffer = '';
    stream.on('data', chunk => { buffer += chunk; });
    stream.on('end', () => {
      logWatchState.offset = stat.size;
      const lines = buffer.split('\n');
      lines.forEach(line => {
        if (line.trim()) processLogLine(line);
      });
    });
  } catch {}
}

// Poll every 3 seconds
setInterval(pollLogs, 3000);
// Initial poll
setTimeout(pollLogs, 1000);

// ─── SETUP / ONBOARDING ─────────────────────────────────────────────────────

let setupState = { step: 'checking', error: null, progress: 0 };

function hasDreamina() { try { fs.accessSync(DREAMINA); return true; } catch { return false; } }

function downloadFile(url, dest) {
  return new Promise((resolve, reject) => {
    const file = fs.createWriteStream(dest);
    https.get(url, (res) => {
      if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
        https.get(res.headers.location, (res2) => { res2.pipe(file); file.on('finish', () => { file.close(); resolve(); }); }).on('error', reject);
        return;
      }
      res.pipe(file);
      file.on('finish', () => { file.close(); resolve(); });
    }).on('error', reject);
  });
}

async function installDreamina() {
  setupState = { step: 'downloading', error: null, progress: 30 };
  try {
    if (!fs.existsSync(BIN_DIR)) fs.mkdirSync(BIN_DIR, { recursive: true });
    await downloadFile(DREAMINA_URL, DREAMINA);
    if (process.platform !== 'win32') fs.chmodSync(DREAMINA, 0o755);
    // Also download SKILL.md
    const skillDir = path.join(HOME, '.dreamina_cli', 'dreamina');
    if (!fs.existsSync(skillDir)) fs.mkdirSync(skillDir, { recursive: true });
    await downloadFile(SKILL_URL, path.join(skillDir, 'SKILL.md'));
    setupState = { step: 'installed', error: null, progress: 60 };
  } catch (e) {
    const fallback = process.platform === 'win32'
      ? 'Manual install: download from https://jimeng.jianying.com/cli'
      : 'Manual install: curl -s https://jimeng.jianying.com/cli | bash';
    setupState = { step: 'error', error: 'Download failed: ' + e.message + '. ' + fallback, progress: 0 };
  }
}

function checkLogin() {
  return new Promise((resolve) => {
    exec('"' + DREAMINA + '" user_credit', { env: ENV, timeout: 15000 }, (err, stdout) => {
      try {
        const data = JSON.parse(stdout);
        if (data && data.total_credit !== undefined) { resolve(true); return; }
      } catch {}
      resolve(false);
    });
  });
}

function startLogin() {
  setupState = { step: 'login', error: null, progress: 80 };
  exec('"' + DREAMINA + '" login', { env: ENV }, () => {});
}

async function runSetup() {
  setupState = { step: 'checking', error: null, progress: 10 };
  if (!hasDreamina()) {
    await installDreamina();
    if (setupState.step === 'error') return;
  }
  const loggedIn = await checkLogin();
  if (loggedIn) {
    setupState = { step: 'ready', error: null, progress: 100 };
  } else {
    setupState = { step: 'login', error: null, progress: 80 };
  }
}

// ─── HEALTH CHECK ───────────────────────────────────────────────────────────

let healthState = { node: { version: process.versions.node, ok: false }, port: { available: false }, cli: { installed: false, path: DREAMINA }, account: { loggedIn: false }, os: { platform: process.platform, arch: process.arch } };

function checkPort(port) {
  return new Promise(function(resolve) {
    var srv = net.createServer();
    srv.once('error', function() { resolve(false); });
    srv.once('listening', function() { srv.close(function() { resolve(true); }); });
    srv.listen(port);
  });
}

async function healthCheck() {
  var nodeVer = parseInt(process.versions.node.split('.')[0], 10);
  healthState.node.ok = nodeVer >= 20;
  if (!healthState.node.ok) {
    console.error('\n  ✗ Node.js ' + process.versions.node + ' — version 20+ required');
    console.error('    Download: https://nodejs.org\n');
    process.exit(1);
  }
  healthState.port.available = await checkPort(PORT);
  if (!healthState.port.available) {
    console.error('\n  ✗ Port ' + PORT + ' already in use. Another monitor instance running?\n');
    process.exit(1);
  }
  healthState.cli.installed = hasDreamina();
  if (healthState.cli.installed) {
    healthState.account.loggedIn = await checkLogin();
  }
  // Terminal output
  console.log('\n  Dreamina Monitor v1.2');
  console.log('  ' + '\u2500'.repeat(21));
  console.log('  ' + (healthState.node.ok ? '\u2713' : '\u2717') + ' Node.js ' + process.versions.node);
  console.log('  ' + (healthState.port.available ? '\u2713' : '\u2717') + ' Port ' + PORT + ' available');
  console.log('  ' + (healthState.cli.installed ? '\u2713' : '\u2717') + ' Dreamina CLI ' + (healthState.cli.installed ? 'found' : 'not found \u2014 downloading...'));
  console.log('  ' + (healthState.account.loggedIn ? '\u2713' : '\u2717') + ' Account ' + (healthState.account.loggedIn ? 'logged in' : 'not logged in \u2014 will prompt'));
  console.log('');
}

// Auto-open browser
function openBrowser() {
  const url = 'http://localhost:' + PORT;
  try {
    if (process.platform === 'win32') exec('start "" "' + url + '"');
    else if (process.platform === 'darwin') exec('open "' + url + '"');
    else exec('xdg-open "' + url + '"');
  } catch {}
}

// readInputs/writeInputs defined above in auto-track section
function saveInputs(data) {
  fs.writeFileSync(INPUTS_FILE, JSON.stringify(data, null, 2), 'utf8');
}

function readSettings() {
  try {
    const saved = JSON.parse(fs.readFileSync(SETTINGS_FILE, 'utf8'));
    const merged = Object.assign({}, DEFAULT_SETTINGS, saved);
    if (merged.downloadDir && !fs.existsSync(merged.downloadDir)) merged.downloadDir = DEFAULT_SETTINGS.downloadDir;
    return merged;
  } catch { return { ...DEFAULT_SETTINGS }; }
}
function writeSettings(data) {
  fs.writeFileSync(SETTINGS_FILE, JSON.stringify(data, null, 2), 'utf8');
}

function run(cmd) {
  return new Promise((resolve) => {
    exec(cmd, { env: ENV, maxBuffer: 4 * 1024 * 1024, timeout: 25000 }, (_err, stdout) => {
      try { resolve(JSON.parse(stdout)); } catch { resolve(null); }
    });
  });
}
function runRaw(cmd) {
  return new Promise((resolve) => {
    exec(cmd, { env: ENV, maxBuffer: 4 * 1024 * 1024, timeout: 60000 }, (err, stdout, stderr) => {
      resolve({ ok: !err, stdout: stdout || '', stderr: stderr || '', code: err ? err.code : 0 });
    });
  });
}

async function getCredits() {
  const data = await run('"' + DREAMINA + '" user_credit');
  if (!data) return null;
  return { total: data.total_credit || 0, vip: data.vip_credit || 0, gift: data.gift_credit || 0, purchase: data.purchase_credit || 0 };
}

// Credit pricing table (verified 2026-04-04)
// Video: model + duration → credits
// Image/upscale: task_type → credits
function estimateCredits(model, duration, taskType) {
  const m = (model || '').toLowerCase();
  const t = (taskType || '').toLowerCase();
  const d = Number(duration) || 0;

  // Image upscale
  if (t === 'image_upscale') return 4;

  // Image generation
  if (t === 'text2image' || t === 'image2image') return 10;

  // Video — VIP models
  if (m.includes('vip')) {
    if (d <= 5) return 20;
    if (d <= 10) return 50;
    return 75;
  }
  // Video — seedance2.0fast (non-vip)
  if (m.includes('fast')) {
    if (d <= 5) return 35;
    if (d <= 10) return 50;
    return 75;
  }
  // Video — seedance2.0 (full quality)
  if (m.includes('seedance') || t.includes('video')) {
    if (d <= 5) return 50;
    if (d <= 10) return 75;
    return 100;
  }
  return 0;
}

async function getStatus() {
  const tasks = await run('"' + DREAMINA + '" list_task --limit=50');
  if (!tasks || !Array.isArray(tasks)) return [];
  const seen = new Set();
  const unique = tasks.filter(t => {
    if (!t.submit_id || seen.has(t.submit_id)) return false;
    seen.add(t.submit_id);
    return ['querying', 'success', 'fail'].includes(t.gen_status);
  });
  const detailed = await Promise.all(
    unique.map(t => run('"' + DREAMINA + '" query_result --submit_id=' + t.submit_id))
  );
  return unique.map((li, i) => {
    const d = detailed[i];
    let credits = (d && d.credit_count) || (li.commerce_info && li.commerce_info.credit_count) || 0;
    const status = (d && d.gen_status) || li.gen_status || 'unknown';
    const qi = (d && d.queue_info) || {};
    const prompt = (d && d.prompt) || li.prompt || '';
    const failReason = (d && d.fail_reason) || li.fail_reason || '';
    const result = (d && (d.result_json || d.result)) || (li.result_json || li.result) || {};
    const videos = result.videos || [];
    const images = result.images || [];
    const queueIdx = (qi.queue_idx !== undefined && qi.queue_idx !== null && qi.queue_length > 0) ? qi.queue_idx : null;
    const queueLen = (qi.queue_length > 0) ? qi.queue_length : null;
    const inputMap = readInputs();
    const tracked = inputMap[li.submit_id] || {};
    const inputFiles = tracked.files || (Array.isArray(tracked) ? tracked : []);
    const taskType = li.gen_task_type || '';
    // For querying tasks: use estimated price (API returns placeholder)
    // For completed tasks: trust API credit_count
    let creditsEstimated = false;
    if (status === 'querying') {
      const est = estimateCredits(tracked.model, tracked.duration, taskType);
      if (est > 0) { credits = est; creditsEstimated = true; }
    }
    const hiddenList = readHidden();
    const isHidden = hiddenList.indexOf(li.submit_id) !== -1;
    if (isHidden) return null;
    const isGhost = credits === 0 && queueIdx === null && status === 'querying';
    return {
      submit_id: li.submit_id, status: status, task_type: li.gen_task_type || '',
      fail_reason: failReason, credits: credits,
      queue_idx: queueIdx, queue_length: queueLen, queue_status: qi.queue_status || '',
      prompt: prompt,
      model: tracked.model || '', ratio: tracked.ratio || '', gen_duration: tracked.duration || '',
      images: images.map(im => ({ url: im.image_url || '', w: im.width || 0, h: im.height || 0 })),
      videos: videos.map(v => ({ url: v.video_url || '', w: v.width || 0, h: v.height || 0 })),
      input_files: inputFiles,
      credits_estimated: creditsEstimated,
      ghost: isGhost
    };
  }).filter(t => t !== null);
}

async function downloadTask(submitId, dir) {
  return runRaw('"' + DREAMINA + '" query_result --submit_id=' + submitId + ' --download_dir="' + dir + '"');
}

function listDir(dirPath) {
  const resolved = path.resolve(dirPath.replace(/\//g, path.sep));
  try {
    const entries = fs.readdirSync(resolved, { withFileTypes: true });
    const dirs = entries
      .filter(e => e.isDirectory() && !e.name.startsWith('.'))
      .map(e => e.name)
      .sort((a, b) => a.toLowerCase().localeCompare(b.toLowerCase()));
    return { ok: true, path: resolved.replace(/\\/g, '/'), dirs: dirs };
  } catch (e) {
    return { ok: false, error: String(e.message || e) };
  }
}

function getDrives() {
  const drives = [];
  for (let i = 65; i <= 90; i++) {
    const letter = String.fromCharCode(i) + ':/';
    try { fs.accessSync(letter); drives.push(letter); } catch {}
  }
  return drives;
}

function readBody(req) {
  return new Promise((resolve, reject) => {
    let body = '';
    req.on('data', chunk => { body += chunk; });
    req.on('end', () => { try { resolve(JSON.parse(body)); } catch { resolve({}); } });
    req.on('error', reject);
  });
}

